diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 9bd6fd0dcc733..8c755c034870e 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -5118,9 +5118,14 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
   if (Depth == MaxAnalysisRecursionDepth)
     return;

+  // True only for ops where NSZ may relax the result zero sign.
+  bool AllowNSZResultRelaxation = false;
   const unsigned Opc = Op->getOpcode();
   switch (Opc) {
   case Instruction::FNeg: {
+    // fneg(fabs(...)) always produces -0 for zero inputs.
+    AllowNSZResultRelaxation =
+        !match(Op->getOperand(0), m_Intrinsic<Intrinsic::fabs>(m_Value()));
     computeKnownFPClass(Op->getOperand(0), DemandedElts, InterestedClasses,
                         Known, Q, Depth + 1);
     Known.fneg();
@@ -5620,6 +5625,7 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
   }
   case Instruction::FAdd:
   case Instruction::FSub: {
+    AllowNSZResultRelaxation = true;
     KnownFPClass KnownLHS, KnownRHS;
     bool WantNegative =
         Op->getOpcode() == Instruction::FAdd &&
@@ -5676,6 +5682,7 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
     break;
   }
   case Instruction::FMul: {
+    AllowNSZResultRelaxation = true;
     const Function *F = cast<Instruction>(Op)->getFunction();
     DenormalMode Mode =
         F ? F->getDenormalMode(
@@ -5724,6 +5731,7 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
   }
   case Instruction::FDiv:
   case Instruction::FRem: {
+    AllowNSZResultRelaxation = true;
     const bool WantNan = (InterestedClasses & fcNan) != fcNone;

     if (Op->getOpcode() == Instruction::FRem)
@@ -6122,6 +6130,30 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
   default:
     break;
   }
+
+  // With no-signed-zeros semantics, +0 and -0 are interchangeable.
+  // If only one sign of logical zero is possible in the result, the other
+  // sign must also be considered possible. Apply this selectively because
+  // some ops preserve or explicitly determine the zero sign.
+  if (const auto *FPOp = dyn_cast_or_null<FPMathOperator>(Op)) {
+    if (FPOp->hasNoSignedZeros() && AllowNSZResultRelaxation) {
+      const auto *I = dyn_cast<Instruction>(Op);
+      const Function *F = I ? I->getFunction() : nullptr;
+      const fltSemantics &FltSem =
+          Op->getType()->getScalarType()->getFltSemantics();
+      DenormalMode Mode =
+          F ? F->getDenormalMode(FltSem) : DenormalMode::getDynamic();
+      bool NeverPosZero = Known.isKnownNeverLogicalPosZero(Mode);
+      bool NeverNegZero = Known.isKnownNeverLogicalNegZero(Mode);
+      if (NeverPosZero != NeverNegZero) {
+        if (NeverPosZero)
+          Known.KnownFPClasses |= fcPosZero;
+        if (NeverNegZero)
+          Known.KnownFPClasses |= fcNegZero;
+        Known.SignBit = std::nullopt;
+      }
+    }
+  }
 }

 KnownFPClass llvm::computeKnownFPClass(const Value *V,

tests.test_body:
; Function Attrs: denormal_fpenv(preservesign)
define float @fadd_double_known_negative_zero_nsz_daz(float noundef nofpclass(ninf pzero sub nnorm) %arg) #0 {
  %add = fadd nsz float %arg, %arg
  ret float %add
}

attributes #0 = { denormal_fpenv(preservesign) }

define float @fsub_self(float noundef %arg) {
  %sub = fsub float %arg, %arg
  ret float %sub
}

; Function Attrs: denormal_fpenv(ieee|dynamic)
define float @fadd_double_known_negative_nonsub_dynamic(float noundef nofpclass(pinf zero sub pnorm) %arg) #0 {
  %add = fadd float %arg, %arg
  ret float %add
}

attributes #0 = { denormal_fpenv(ieee|dynamic) }

define float @fadd_double_known_negative_zero_nsz(float noundef nofpclass(ninf pzero sub nnorm) %arg) {
  %add = fadd nsz float %arg, %arg
  ret float %add
}

define i1 @test_fabs_used_is_fpclass_pzero(float %x) {
  %cmp = fcmp oge float %x, 0.000000e+00
  %neg = fneg float %x
  %sel = select i1 %cmp, float %x, float %neg
  %is_fpclass = call i1 @llvm.is.fpclass.f32(float %sel, i32 64)
  ret i1 %is_fpclass
}

; Function Attrs: nocallback nocreateundeforpoison nofree nosync nounwind speculatable willreturn memory(none)
declare i1 @llvm.is.fpclass.f32(float, i32 immarg) #0

attributes #0 = { nocallback nocreateundeforpoison nofree nosync nounwind speculatable willreturn memory(none) }
